// ============================================================
// NODE: Validate & Route Incoming Webhook
// ============================================================

const body = $input.first().json.body;

// Handle Meta Webhook Verification
if ($input.first().json.query?.['hub.mode'] === 'subscribe') {
  return [{ json: { type: 'verification', challenge: $input.first().json.query['hub.challenge'] } }];
}

// Validate WhatsApp Message Structure
if (!body?.entry?.[0]?.changes?.[0]?.value?.messages) {
  return [{ json: { type: 'non_message', raw: body } }];
}

const change = body.entry[0].changes[0].value;
const message = change.messages[0];
const contact = change.contacts?.[0];
const wabaId = body.entry[0].id;

return [{
  json: {
    type: 'message',
    waba_id: wabaId,
    phone_number_id: change.metadata.phone_number_id,
    message_id: message.id,
    from_phone: message.from,
    from_name: contact?.profile?.name || 'Unknown',
    message_type: message.type,
    message_text: message.text?.body || '',
    timestamp: message.timestamp
  }
}];

// ============================================================
// NODE: Find client by WABA ID + Run Guard Checks
// ============================================================

const firebaseResp = $input.first().json;
const messageData = $('🔍 Validate & Extract Payload').first().json;
const docs = firebaseResp.documents || [];

// Find client matching the incoming WABA ID
let client = null;
for (const doc of docs) {
  const fields = doc.fields || {};
  const wabaField = fields?.whatsapp_config?.mapValue?.fields?.waba_id?.stringValue;
  if (wabaField === messageData.waba_id) {
    // Parse Firebase document fields into clean object
    client = {
      client_id: fields.client_id?.stringValue,
      business_name: fields.business_name?.stringValue,
      whatsapp_config: {
        phone_number_id: fields.whatsapp_config?.mapValue?.fields?.phone_number_id?.stringValue,
        waba_id: fields.whatsapp_config?.mapValue?.fields?.waba_id?.stringValue,
        access_token: fields.whatsapp_config?.mapValue?.fields?.access_token?.stringValue
      },
      subscription: {
        status: fields.subscription?.mapValue?.fields?.status?.stringValue,
        expiry_date: fields.subscription?.mapValue?.fields?.expiry_date?.stringValue,
        plan: fields.subscription?.mapValue?.fields?.plan?.stringValue
      },
      ai_config: {
        language_mode: fields.ai_config?.mapValue?.fields?.language_mode?.stringValue || 'auto',
        forced_language: fields.ai_config?.mapValue?.fields?.forced_language?.stringValue || null,
        arcee_model: fields.ai_config?.mapValue?.fields?.arcee_model?.stringValue || 'arcee-blaze',
        temperature: parseFloat(fields.ai_config?.mapValue?.fields?.temperature?.doubleValue || 0.7),
        max_tokens: parseInt(fields.ai_config?.mapValue?.fields?.max_tokens?.integerValue || 1024),
        system_prompt: fields.ai_config?.mapValue?.fields?.system_prompt?.stringValue,
        brand_name: fields.ai_config?.mapValue?.fields?.brand_name?.stringValue
      },
      safety_config: {
        guardrails_enabled: fields.safety_config?.mapValue?.fields?.guardrails_enabled?.booleanValue ?? true,
        blocked_topics: (fields.safety_config?.mapValue?.fields?.blocked_topics?.arrayValue?.values || []).map(v => v.stringValue)
      },
      status: {
        is_active: fields.status?.mapValue?.fields?.is_active?.booleanValue ?? true,
        kill_switch: fields.status?.mapValue?.fields?.kill_switch?.booleanValue ?? false
      }
    };
    break;
  }
}

if (!client) {
  return [{ json: { blocked: true, reason: 'CLIENT_NOT_FOUND', message_data: messageData } }];
}

// Guard: Kill Switch
if (client.status.kill_switch) {
  return [{ json: { blocked: true, reason: 'CLIENT_KILL_SWITCH', client, message_data: messageData } }];
}

// Guard: Subscription Expiry
const now = new Date();
const expiry = new Date(client.subscription.expiry_date);
if (expiry < now) {
  return [{ json: { blocked: true, reason: 'SUBSCRIPTION_EXPIRED', client, message_data: messageData } }];
}

return [{ json: { blocked: false, client, message_data: messageData } }];

// ============================================================
// NODE: Safety Filter — Blocks sensitive topics
// ============================================================

const { client, message_data } = $input.first().json;
const text = message_data.message_text.toLowerCase();
const safetyConfig = client.safety_config;

if (!safetyConfig?.guardrails_enabled) {
  return [{ json: { safe: true, client, message_data } }];
}

const BLOCKED_PATTERNS = {
  politics: [
    /\b(سياس|انتخاب|حزب|رئيس|برلمان|ثورة|احتجاج|معارضة)\b/i,
    /\b(politique|élection|parti|président|parlement|révolution)\b/i,
    /\b(politic|election|party|president|parliament|revolution)\b/i
  ],
  religion: [
    /\b(دين|إسلام|مسيح|يهود|فتوى|حلال|حرام|كفر|شيعة|سنة)\b/i,
    /\b(religion|islam|chrétien|juif|fatwa|halal|haram)\b/i,
    /\b(religion|islam|christian|jewish|fatwa|halal|haram)\b/i
  ],
  adult_content: [ /\b(sex|nude|xxx|porn|escort)\b/i, /\b(جنس|عاري|بورن|دعارة)\b/i ],
  violence: [
    /\b(bomb|weapon|kill|terrorist|attack)\b/i,
    /\b(قنبلة|سلاح|إرهاب|قتل|هجوم)\b/i
  ]
};

const blockedTopics = safetyConfig.blocked_topics || ['politics','religion','adult_content','violence'];
let detectedTopic = null;

for (const topic of blockedTopics) {
  if (BLOCKED_PATTERNS[topic]) {
    for (const pattern of BLOCKED_PATTERNS[topic]) {
      if (pattern.test(text)) { detectedTopic = topic; break; }
    }
  }
  if (detectedTopic) break;
}

if (detectedTopic) {
  return [{ json: { safe: false, detected_topic: detectedTopic, client, message_data } }];
}

return [{ json: { safe: true, client, message_data } }];

// ============================================================
// NODE: Multi-Lingual Auto-Detection (AR / FR / EN)
// ============================================================

const { client, message_data } = $input.first().json;
const text = message_data.message_text;
const aiConfig = client.ai_config;

// Manual Override check
if (aiConfig.language_mode === 'manual' && aiConfig.forced_language) {
  return [{ json: {
    language: aiConfig.forced_language,
    detection_method: 'manual_override',
    client, message_data
  }}];
}

// Auto-Detection
const arabicScore  = (text.match(/[\u0600-\u06FF]/g) || []).length;
const frenchScore  = (text.match(/\b(je|tu|il|nous|vous|le|la|les|de|du|est|bonjour|merci|comment|votre)\b/gi) || []).length;
const englishScore = (text.match(/\b(i|you|he|she|we|the|is|are|hello|hi|thank|how|please|help)\b/gi) || []).length;

let language = 'ar';
if (arabicScore > 2) language = 'ar';
else if (frenchScore >= englishScore && frenchScore > 0) language = 'fr';
else if (englishScore > 0) language = 'en';

return [{ json: { language, detection_method: 'auto', client, message_data } }];

// ============================================================
// NODE: Build Arcee Prompt
// Constructs the full prompt for Arcee AI
// ============================================================

const { client, message_data, language } = $input.first().json;
const aiConfig = client.ai_config;

const langInstructions = {
  ar: 'يجب أن تكون جميع ردودك باللغة العربية. استخدم أسلوباً احترافياً وودوداً.',
  fr: 'Toutes vos réponses doivent être en français, de manière professionnelle.',
  en: 'All your responses must be in English, professional and friendly.'
};

const systemPrompt = `${aiConfig.system_prompt || 'أنت مساعد ذكي احترافي.'}

--- قاعدة اللغة الإلزامية ---
${langInstructions[language || 'ar']}

--- إرشادات العلامة التجارية ---
اسم العلامة: ${aiConfig.brand_name || client.business_name}
ناقش فقط المواضيع المتعلقة بهذا العمل التجاري.
لا تذكر أبداً المنافسين.
لا تناقش السياسة أو الدين أو المواضيع الحساسة.
إذا سُئلت هل أنت ذكاء اصطناعي: أجب بـ "أنا مساعدك الرقمي" فقط.`;

return [{ json: {
  system_prompt: systemPrompt,
  user_message: message_data.message_text,
  language,
  arcee_model: aiConfig.arcee_model || 'arcee-blaze',
  temperature: aiConfig.temperature || 0.7,
  max_tokens: aiConfig.max_tokens || 1024,
  client,
  message_data
}}];

// ============================================================
// NODE: Extract Arcee Response
// Arcee uses same format as OpenAI
// ============================================================

const arceeResp = $input.first().json;
const promptData = $('📝 Build Arcee Prompt').first().json;

// Extract text from Arcee response (OpenAI-compatible format)
const aiText = arceeResp.choices?.[0]?.message?.content ||
               arceeResp.choices?.[0]?.text ||
               'عذراً، حدث خطأ تقني. يرجى المحاولة مرة أخرى.';

const client = promptData.client;
const messageData = promptData.message_data;

// Build WhatsApp message payload
const whatsappPayload = {
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: messageData.from_phone,
  type: 'text',
  text: { body: aiText, preview_url: false }
};

return [{ json: {
  payload: whatsappPayload,
  phone_number_id: client.whatsapp_config.phone_number_id,
  access_token: client.whatsapp_config.access_token,
  ai_response: aiText,
  client,
  message_data: messageData
}}];

// Save conversation + Update analytics via Firebase REST
const sendResult = $input.first().json;
const formatData = $('💬 Format Reply').first().json;
const now = new Date().toISOString();

// Build Firestore document update
const docId = `${formatData.client.client_id}_${formatData.message_data.from_phone.replace('+','')}` ;

return [{ json: {
  doc_id: docId,
  client_id: formatData.client.client_id,
  user_phone: formatData.message_data.from_phone,
  user_message: formatData.message_data.message_text,
  ai_response: formatData.ai_response,
  timestamp: now,
  language: $('🌍 Language Detection').first().json.language
}}];

// Send blocked/expired message
const blockData = $input.first().json;
const client = blockData.client;
const messageData = blockData.message_data;

const MESSAGES = {
  CLIENT_NOT_FOUND:     { ar: 'عذراً، هذه الخدمة غير متاحة حالياً.' },
  CLIENT_KILL_SWITCH:   { ar: 'الخدمة موقوفة مؤقتاً. للمساعدة تواصل معنا.' },
  SUBSCRIPTION_EXPIRED: { ar: 'انتهت صلاحية الاشتراك. يرجى التجديد للاستمرار.' },
  MAINTENANCE_MODE:     { ar: 'الخدمة تحت الصيانة. نعود قريباً.' }
};

const msg = MESSAGES[blockData.reason]?.ar || 'الخدمة غير متاحة.';

return [{ json: {
  payload: {
    messaging_product: 'whatsapp',
    to: messageData?.from_phone,
    type: 'text',
    text: { body: msg }
  },
  phone_number_id: client?.whatsapp_config?.phone_number_id,
  access_token: client?.whatsapp_config?.access_token
}}];
